    request = OcrRequest.from_json("{\"document\":{\"type\":\"document_url\",\"url\":\"https://example.com/multipage.pdf\"},\"model\":\"mistral/mistral-ocr-latest\"}")

    result = await client.ocr(request)
    assert len(result.pages) == 2  # noqa: S101
    assert result.pages[0].index == 0  # noqa: S101
